-- schema-v19-descriptions-surfing.sql: Extended English descriptions for surfing category (world 100)
-- Each description_en 500-700 characters: why world 100, wave type, season, hazards, where and when to surf.

UPDATE challenges SET description_en = 'Banzai Pipeline on Oahu''s North Shore is the world''s most famous and dangerous wave: hollow tubes over a shallow reef. Winter (December–February) brings the biggest swells and the Vans Triple Crown. The wave has claimed lives; only experts should surf it. Watch from the beach or join the pro event. Pipeline is the ultimate barrel and one of the world''s top 100 surf spots.' WHERE category = 'surfing' AND title_en = 'Banzai Pipeline';

UPDATE challenges SET description_en = 'Teahupoo in Tahiti is one of the heaviest waves on Earth: a thick slab over shallow reef. The Billabong Pro has been held here. The wave is brutal and can hold 20 ft faces. Access is by boat; the village is small. Teahupoo is for experts only and one of the world''s most iconic and dangerous surf spots. Respect the ocean and local culture.' WHERE category = 'surfing' AND title_en = 'Teahupoo';

UPDATE challenges SET description_en = 'Jaws (Pe''ahi) on Maui is the tow-in wave that pioneered big-wave surfing. Faces can reach 20 m; winter swells are the trigger. Tow-in jetskis are used to catch the wave. The spot is on the north shore; access and safety require experience. Jaws is one of the world''s most legendary big-wave spots and a top 100 destination.' WHERE category = 'surfing' AND title_en = 'Jaws (Pe''ahi)';

UPDATE challenges SET description_en = 'Nazare in Portugal is where the Atlantic funnels into a canyon to produce 100 ft+ waves. Praia do Norte and the cliff view are iconic. Big-wave surfers have set records here. Winter is the season; the town is a surf pilgrimage. Nazare is one of the world''s most dramatic and photographed surf spots and a top 100 destination.' WHERE category = 'surfing' AND title_en = 'Nazare';

